// entity 1 — player spawn (far west, facing +X toward the dummy line and the
// enemy). Tagged `player`, the EXCLUSIVE target of the combat-demo-reaction.ts
// `applyDamage` reaction. The player archetype declares health (max 100) but NO
// hitbox, so this tag is never matched by a weapon ray — only by the named
// retaliation reaction. The enemy (entity 7) is far east behind the center
// pillar, so reaching the player requires routing around it (A* + funnel).
{
"classname" "player_spawn"
"origin" "80 256 24"
"angles" "0 0 0"
"_tags" "player"
}
// entity 2 — target dummy (in front of the player so the reference pistol's
// hitscan ray can reach it). Carries health (max 30) + hitbox; three 12-damage
// hits despawn it. Tagged `dummy` (EXCLUSIVE to the dummies) so it counts toward
// the progress threshold.
{
"classname" "target_dummy"
"origin" "200 200 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 3 — target dummy.
{
"classname" "target_dummy"
