"classname" "target_dummy"
"origin" "200 280 16"
"angles" "0 180 0"
"_tags" "dummy"
}
// entity 5 — target dummy. Four dummies, fraction 0.5 means two kills fire
// `dummiesCleared`, which routes 35 damage to the `player` tag.
{
"classname" "target_dummy"
"origin" "200 320 16"
"angles" "0 180 0"
"_tags" "dummy"
}
